            console.log(finalTime);

            while( finalTime > Date.now()){

                console.log(Date.now);

                if(finalTime === Date.now()){
                    console.log('pelo amor de Deus');
                }
            }
            
        }else if(e.type === 'mouseleave'){
                
        }
    }


    return {
        hoverConfig,
    }


}
